import{_ as d,o,c as e,ag as r}from"./chunks/framework.PErH1-Uo.js";const p=JSON.parse('{"title":"Comandos Linux por Categorías","description":"","frontmatter":{},"headers":[],"relativePath":"linux/linux/comandos_linux.md","filePath":"linux/linux/comandos_linux.md","lastUpdated":1775402759000}'),a={name:"linux/linux/comandos_linux.md"};function c(s,t,i,n,h,u){return o(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="comandos-linux-por-categorias" tabindex="-1">Comandos Linux por Categorías <a class="header-anchor" href="#comandos-linux-por-categorias" aria-label="Permalink to &quot;Comandos Linux por Categorías&quot;">​</a></h1><h2 id="_1-navegacion-por-el-sistema-de-archivos" tabindex="-1">1. <strong>Navegación por el sistema de archivos</strong> <a class="header-anchor" href="#_1-navegacion-por-el-sistema-de-archivos" aria-label="Permalink to &quot;1. **Navegación por el sistema de archivos**&quot;">​</a></h2><table tabindex="0"><thead><tr><th><strong>Comando</strong></th><th><strong>Descripción</strong></th><th><strong>Ejemplo</strong></th></tr></thead><tbody><tr><td><code>pwd</code></td><td>Muestra la ruta del directorio actual.</td><td><code>pwd</code></td></tr><tr><td><code>ls</code></td><td>Lista archivos y carpetas.</td><td><code>ls -l</code></td></tr><tr><td><code>cd</code></td><td>Cambia de directorio.</td><td><code>cd Documentos</code></td></tr><tr><td><code>tree</code></td><td>Muestra estructura de carpetas en forma de árbol.</td><td><code>tree</code></td></tr></tbody></table><hr><h2 id="_2-gestion-de-archivos-y-directorios" tabindex="-1">2. <strong>Gestión de archivos y directorios</strong> <a class="header-anchor" href="#_2-gestion-de-archivos-y-directorios" aria-label="Permalink to &quot;2. **Gestión de archivos y directorios**&quot;">​</a></h2><table tabindex="0"><thead><tr><th><strong>Comando</strong></th><th><strong>Descripción</strong></th><th><strong>Ejemplo</strong></th></tr></thead><tbody><tr><td><code>touch</code></td><td>Crea un archivo vacío.</td><td><code>touch notas.txt</code></td></tr><tr><td><code>mkdir</code></td><td>Crea un directorio.</td><td><code>mkdir proyectos</code></td></tr><tr><td><code>cp</code></td><td>Copia archivos o carpetas.</td><td><code>cp archivo.txt copia.txt</code></td></tr><tr><td><code>mv</code></td><td>Mueve o renombra archivos/carpetas.</td><td><code>mv archivo.txt carpeta/</code></td></tr><tr><td><code>rm</code></td><td>Borra archivos.</td><td><code>rm archivo.txt</code></td></tr><tr><td><code>rm -r</code></td><td>Borra carpetas y su contenido. ⚠️</td><td><code>rm -r carpeta</code></td></tr><tr><td><code>nano</code></td><td>Editor de texto en terminal.</td><td><code>nano notas.txt</code></td></tr><tr><td><code>cat</code></td><td>Muestra el contenido de un archivo.</td><td><code>cat notas.txt</code></td></tr><tr><td><code>more</code></td><td>Muestra texto página por página.</td><td><code>more documento.txt</code></td></tr><tr><td><code>less</code></td><td>Similar a <code>more</code>, permite desplazamiento.</td><td><code>less documento.txt</code></td></tr></tbody></table><hr><h2 id="_3-permisos-y-propietarios" tabindex="-1">3. <strong>Permisos y propietarios</strong> <a class="header-anchor" href="#_3-permisos-y-propietarios" aria-label="Permalink to &quot;3. **Permisos y propietarios**&quot;">​</a></h2><table tabindex="0"><thead><tr><th><strong>Comando</strong></th><th><strong>Descripción</strong></th><th><strong>Ejemplo</strong></th></tr></thead><tbody><tr><td><code>ls -l</code></td><td>Muestra permisos y detalles de archivos.</td><td><code>ls -l</code></td></tr><tr><td><code>chmod</code></td><td>Cambia permisos de un archivo.</td><td><code>chmod 755 script.sh</code></td></tr><tr><td><code>chown</code></td><td>Cambia el propietario de un archivo.</td><td><code>chown usuario archivo.txt</code></td></tr><tr><td><code>chgrp</code></td><td>Cambia el grupo de un archivo.</td><td><code>chgrp alumnos archivo.txt</code></td></tr></tbody></table><hr><h2 id="_4-busqueda-de-archivos-y-texto" tabindex="-1">4. <strong>Búsqueda de archivos y texto</strong> <a class="header-anchor" href="#_4-busqueda-de-archivos-y-texto" aria-label="Permalink to &quot;4. **Búsqueda de archivos y texto**&quot;">​</a></h2><table tabindex="0"><thead><tr><th><strong>Comando</strong></th><th><strong>Descripción</strong></th><th><strong>Ejemplo</strong></th></tr></thead><tbody><tr><td><code>find</code></td><td>Busca archivos y directorios.</td><td><code>find /home -name &quot;notas.txt&quot;</code></td></tr><tr><td><code>locate</code></td><td>Busca archivos usando una base de datos.</td><td><code>locate notas.txt</code></td></tr><tr><td><code>grep</code></td><td>Busca texto dentro de archivos.</td><td><code>grep &quot;palabra&quot; archivo.txt</code></td></tr><tr><td><code>grep -r</code></td><td>Busca texto en carpetas recursivamente.</td><td><code>grep -r &quot;error&quot; /var/log</code></td></tr></tbody></table><hr><h2 id="_5-procesos-y-sistema" tabindex="-1">5. <strong>Procesos y sistema</strong> <a class="header-anchor" href="#_5-procesos-y-sistema" aria-label="Permalink to &quot;5. **Procesos y sistema**&quot;">​</a></h2><table tabindex="0"><thead><tr><th><strong>Comando</strong></th><th><strong>Descripción</strong></th><th><strong>Ejemplo</strong></th></tr></thead><tbody><tr><td><code>ps</code></td><td>Muestra procesos activos.</td><td><code>ps aux</code></td></tr><tr><td><code>top</code></td><td>Monitorea procesos en tiempo real.</td><td><code>top</code></td></tr><tr><td><code>htop</code></td><td>Similar a <code>top</code>, pero más visual.</td><td><code>htop</code></td></tr><tr><td><code>kill</code></td><td>Finaliza procesos por PID.</td><td><code>kill 1234</code></td></tr><tr><td><code>uptime</code></td><td>Tiempo encendido del sistema.</td><td><code>uptime</code></td></tr><tr><td><code>free</code></td><td>Muestra memoria usada y libre.</td><td><code>free -h</code></td></tr><tr><td><code>df</code></td><td>Muestra espacio en disco.</td><td><code>df -h</code></td></tr><tr><td><code>uname</code></td><td>Información del sistema.</td><td><code>uname -a</code></td></tr></tbody></table><hr><h2 id="_6-red-y-conectividad" tabindex="-1">6. <strong>Red y conectividad</strong> <a class="header-anchor" href="#_6-red-y-conectividad" aria-label="Permalink to &quot;6. **Red y conectividad**&quot;">​</a></h2><table tabindex="0"><thead><tr><th><strong>Comando</strong></th><th><strong>Descripción</strong></th><th><strong>Ejemplo</strong></th></tr></thead><tbody><tr><td><code>ping</code></td><td>Verifica conectividad a un host.</td><td><code>ping google.com</code></td></tr><tr><td><code>ifconfig</code> <em>(obsoleto, usar <code>ip</code>)</em></td><td>Muestra configuración de red.</td><td><code>ifconfig</code></td></tr><tr><td><code>ip a</code></td><td>Muestra interfaces de red.</td><td><code>ip a</code></td></tr><tr><td><code>netstat</code> <em>(obsoleto, usar <code>ss</code>)</em></td><td>Muestra conexiones de red.</td><td><code>netstat -tuln</code></td></tr><tr><td><code>ss</code></td><td>Alternativa moderna a <code>netstat</code>.</td><td><code>ss -tuln</code></td></tr><tr><td><code>curl</code></td><td>Descarga contenido desde la web.</td><td><code>curl https://example.com</code></td></tr><tr><td><code>wget</code></td><td>Descarga archivos desde la web.</td><td><code>wget archivo.zip</code></td></tr></tbody></table><hr><h2 id="_7-gestion-de-paquetes" tabindex="-1">7. <strong>Gestión de paquetes</strong> <a class="header-anchor" href="#_7-gestion-de-paquetes" aria-label="Permalink to &quot;7. **Gestión de paquetes**&quot;">​</a></h2><table tabindex="0"><thead><tr><th><strong>Comando</strong></th><th><strong>Descripción</strong></th><th><strong>Ejemplo</strong></th></tr></thead><tbody><tr><td><code>apt update</code></td><td>Actualiza lista de paquetes (Debian/Ubuntu).</td><td><code>sudo apt update</code></td></tr><tr><td><code>apt upgrade</code></td><td>Actualiza programas instalados.</td><td><code>sudo apt upgrade</code></td></tr><tr><td><code>apt install</code></td><td>Instala un paquete.</td><td><code>sudo apt install htop</code></td></tr><tr><td><code>apt remove</code></td><td>Elimina un paquete.</td><td><code>sudo apt remove nano</code></td></tr><tr><td><code>dnf install</code></td><td>Instala paquetes (Fedora/RHEL).</td><td><code>sudo dnf install htop</code></td></tr></tbody></table><hr><h2 id="_8-compresion-y-descompresion" tabindex="-1">8. <strong>Compresión y descompresión</strong> <a class="header-anchor" href="#_8-compresion-y-descompresion" aria-label="Permalink to &quot;8. **Compresión y descompresión**&quot;">​</a></h2><table tabindex="0"><thead><tr><th><strong>Comando</strong></th><th><strong>Descripción</strong></th><th><strong>Ejemplo</strong></th></tr></thead><tbody><tr><td><code>tar -cvf</code></td><td>Crea un archivo <code>.tar</code>.</td><td><code>tar -cvf backup.tar carpeta/</code></td></tr><tr><td><code>tar -xvf</code></td><td>Extrae un archivo <code>.tar</code>.</td><td><code>tar -xvf backup.tar</code></td></tr><tr><td><code>gzip</code></td><td>Comprime archivos <code>.gz</code>.</td><td><code>gzip archivo.txt</code></td></tr><tr><td><code>gunzip</code></td><td>Descomprime archivos <code>.gz</code>.</td><td><code>gunzip archivo.txt.gz</code></td></tr><tr><td><code>zip</code></td><td>Comprime en <code>.zip</code>.</td><td><code>zip archivo.zip archivo.txt</code></td></tr><tr><td><code>unzip</code></td><td>Descomprime <code>.zip</code>.</td><td><code>unzip archivo.zip</code></td></tr></tbody></table><hr><h2 id="_9-comandos-para-usuarios-y-grupos" tabindex="-1">9. <strong>Comandos para usuarios y grupos</strong> <a class="header-anchor" href="#_9-comandos-para-usuarios-y-grupos" aria-label="Permalink to &quot;9. **Comandos para usuarios y grupos**&quot;">​</a></h2><table tabindex="0"><thead><tr><th><strong>Comando</strong></th><th><strong>Descripción</strong></th><th><strong>Ejemplo</strong></th></tr></thead><tbody><tr><td><code>whoami</code></td><td>Muestra el usuario actual.</td><td><code>whoami</code></td></tr><tr><td><code>who</code></td><td>Lista usuarios conectados.</td><td><code>who</code></td></tr><tr><td><code>id</code></td><td>Muestra UID y GID del usuario actual.</td><td><code>id</code></td></tr><tr><td><code>adduser</code></td><td>Crea un nuevo usuario.</td><td><code>sudo adduser alumno</code></td></tr><tr><td><code>passwd</code></td><td>Cambia contraseña de usuario.</td><td><code>passwd</code></td></tr><tr><td><code>groups</code></td><td>Muestra grupos a los que pertenece un usuario.</td><td><code>groups</code></td></tr></tbody></table><hr><h2 id="_10-superusuario-y-administracion" tabindex="-1">10. <strong>Superusuario y administración</strong> <a class="header-anchor" href="#_10-superusuario-y-administracion" aria-label="Permalink to &quot;10. **Superusuario y administración**&quot;">​</a></h2><table tabindex="0"><thead><tr><th><strong>Comando</strong></th><th><strong>Descripción</strong></th><th><strong>Ejemplo</strong></th></tr></thead><tbody><tr><td><code>sudo</code></td><td>Ejecuta comandos como administrador.</td><td><code>sudo apt update</code></td></tr><tr><td><code>su</code></td><td>Cambia a otro usuario (superusuario).</td><td><code>su root</code></td></tr><tr><td><code>history</code></td><td>Muestra historial de comandos.</td><td><code>history</code></td></tr><tr><td><code>clear</code></td><td>Limpia la terminal.</td><td><code>clear</code></td></tr></tbody></table><hr><h2 id="_11-atajos-utiles-en-terminal" tabindex="-1">11. <strong>Atajos útiles en terminal</strong> <a class="header-anchor" href="#_11-atajos-utiles-en-terminal" aria-label="Permalink to &quot;11. **Atajos útiles en terminal**&quot;">​</a></h2><table tabindex="0"><thead><tr><th><strong>Tecla</strong></th><th><strong>Función</strong></th></tr></thead><tbody><tr><td><code>Ctrl + C</code></td><td>Detiene un comando en ejecución.</td></tr><tr><td><code>Ctrl + Z</code></td><td>Suspende un proceso.</td></tr><tr><td><code>Ctrl + D</code></td><td>Cierra la sesión actual.</td></tr><tr><td><code>↑</code> / <code>↓</code></td><td>Navega por historial de comandos.</td></tr><tr><td><code>Tab</code></td><td>Autocompleta nombres de archivos/carpetas.</td></tr></tbody></table>',33)])])}const m=d(a,[["render",c]]);export{p as __pageData,m as default};
